queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?element_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasElements ?child ; p:hasProduction_Designers ?parent . } GROUP BY ?child }
  ?child p:element_type ?element_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Production_Designers } }
  FILTER(?nf = ?total)
}

